  graduation_benchmarks = '{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2500+ ft/hr (elite level)","whyThisTarget":"Overshoot target for 7,000 ft objective ensures comfortable sustained uphill power."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"15+ miles (strong level)","whyThisTarget":"Aerobic base overshoot for 12-mile objective builds deep endurance reserves."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000003","exerciseName":"Weighted Pull-Ups","graduationTarget":"5 reps @ +25lb (strong level)","whyThisTarget":"Sustained grip strength needed for 5.5 moves while managing pack weight."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500m @ 70lb in 10 minutes","whyThisTarget":"Pack carrying endurance for technical terrain with climbing gear load."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 reps per leg (strong level)","whyThisTarget":"Knee stability and control for exposed descents and awkward positions."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000001","exerciseName":"Top-Rope Climbing Assessment","graduationTarget":"5.7+ clean sends","whyThisTarget":"Two sub-grades above 5.5 objective ensures comfortable movement margin."},{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4/5 confidence rating","whyThisTarget":"High exposure comfort essential for Upper Exum''s serious consequences."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90 seconds (strong level)","whyThisTarget":"Hip and ankle mobility for high steps and rest positions during long route."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5 inches (strong level)","whyThisTarget":"Ankle mobility prevents injury on steep granite and technical descents."}]}'
